const API_URL = "http://localhost:8080/api/auth/login";

export const loginUsuario = async (matricula, password) => {
    try {
        const response = await fetch(API_URL, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ matricula, password })
        });

        // CAMBIO AQUÍ: Usa .text() porque el Backend envía un String plano
        const data = await response.text(); 
        return data; // Devolverá "BIENVENIDO_ADMIN", "ERROR_PASSWORD", etc.

    } catch (error) {
        console.error("Error real en la consola:", error);
        return "ERROR_CONEXION";
    }
};
